## FTS5 Query Escaping
```javascript
/**
 * Escape special FTS5 characters to prevent syntax errors
 * FTS5 special: " * ^ - : ( ) AND OR NOT NEAR
 */
function escapeFts5Query(query) {
    return query
        .split(/\s+/)
        .filter(term => term.length > 0)
        .map(term => {
            // Escape embedded double-quotes
            const escaped = term.replace(/"/g, '""');
            // Wrap in quotes to treat as literal
            return `"${escaped}"`;
        })
        .join(' ');
}

/**
 * For prefix search (autocomplete), append * to last term
 */
function escapeFts5Prefix(query) {
    const terms = query.split(/\s+/).filter(t => t.length > 0);
    if (terms.length === 0) return '';

    const lastTerm = terms.pop();
    const escaped = terms.map(t => `"${t.replace(/"/g, '""')}"`);
    escaped.push(`"${lastTerm.replace(/"/g, '""')}"*`);
    return escaped.join(' ');
}
```

