use criterion::{criterion_group, criterion_main, Criterion, BenchmarkId};

fn benchmark_dot_product(c: &mut Criterion) {
    let mut group = c.benchmark_group("dot_product_f16");

    for dim in [128, 256, 384, 512, 768, 1024, 1536] {
        let a: Vec<f16> = (0..dim).map(|i| f16::from_f32((i as f32).sin())).collect();
        let b: Vec<f16> = (0..dim).map(|i| f16::from_f32((i as f32).cos())).collect();

        group.bench_with_input(BenchmarkId::new("scalar", dim), &dim, |bench, _| {
            bench.iter(|| dot_product_scalar(&a, &b))
        });

        group.bench_with_input(BenchmarkId::new("simd", dim), &dim, |bench, _| {
            bench.iter(|| dot_product_f16_simd(&a, &b))
        });
    }

    group.finish();
}

criterion_group!(benches, benchmark_dot_product);
criterion_main!(benches);
```

